function formatExpiryDate(input) {
    // Remove all non-digit characters
    let value = input.value.replace(/\D/g, '');

    // Insert a slash after the second digit (MM) if it's long enough
    if (value.length >= 3) {
        value = value.slice(0, 2) + '/' + value.slice(2, 6);
    }

    input.value = value;
}
</script>
